import{_ as a,a as e,b as d,c as o}from"./chunks/查询额度成功.BYPQR2qF.js";import{_ as i,o as r,c as n,a2 as s}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"إضافة قناة WebDAV","description":"","frontmatter":{},"headers":[],"relativePath":"ar-SA/upload/webdav.md","filePath":"ar-SA/upload/webdav.md","lastUpdated":1781962217000}'),l={name:"ar-SA/upload/webdav.md"};function p(c,t,h,b,m,u){return r(),n("div",null,[...t[0]||(t[0]=[s('<h1 id="إضافة-قناة-webdav" tabindex="-1">إضافة قناة WebDAV <a class="header-anchor" href="#إضافة-قناة-webdav" aria-label="Permalink to &quot;إضافة قناة WebDAV&quot;">​</a></h1><h2 id="متى-تكون-مناسبة؟" tabindex="-1">متى تكون مناسبة؟ <a class="header-anchor" href="#متى-تكون-مناسبة؟" aria-label="Permalink to &quot;متى تكون مناسبة؟&quot;">​</a></h2><p>استخدم قناة WebDAV عندما:</p><ul><li>لديك NAS أو قرص سحابي أو خدمة تخزين توفر WebDAV endpoint.</li><li>تريد حفظ الصور المرفوعة داخل مجلد WebDAV خاص بك.</li><li>تريد حفظ بيانات الاعتماد في جدول D1 <code>upload_channels</code> بدل بقائها مكشوفة طويلًا في الواجهة الأمامية.</li></ul><h2 id="ما-الذي-تحتاجه-قبل-البدء؟" tabindex="-1">ما الذي تحتاجه قبل البدء؟ <a class="header-anchor" href="#ما-الذي-تحتاجه-قبل-البدء؟" aria-label="Permalink to &quot;ما الذي تحتاجه قبل البدء؟&quot;">​</a></h2><table tabindex="0"><thead><tr><th>المتطلب</th><th>الغرض</th></tr></thead><tbody><tr><td>WebDAV Endpoint</td><td>عنوان WebDAV من جهة الخادم، مثل <code>https://nas.example.com/dav</code>.</td></tr><tr><td>Username</td><td>اسم المستخدم لتسجيل الدخول إلى خدمة WebDAV.</td></tr><tr><td>Password</td><td>كلمة المرور لتسجيل الدخول إلى خدمة WebDAV.</td></tr><tr><td>Authentication mode</td><td>الافتراضي <code>Basic</code>. استخدم <code>Digest</code> أو التفاوض التلقائي فقط إذا طلب الخادم ذلك.</td></tr><tr><td>Storage directory</td><td>المجلد المستخدم لتخزين الملفات. الافتراضي <code>imgbed</code>.</td></tr></tbody></table><h2 id="أين-تضيفها؟" tabindex="-1">أين تضيفها؟ <a class="header-anchor" href="#أين-تضيفها؟" aria-label="Permalink to &quot;أين تضيفها؟&quot;">​</a></h2><ol><li>افتح إعدادات النظام.</li><li>انتقل إلى إعدادات الرفع.</li><li>اضغط Add Channel في الزاوية العلوية اليمنى.</li><li>اختر <code>WebDAV</code>.</li></ol><h2 id="شرح-الحقول" tabindex="-1">شرح الحقول <a class="header-anchor" href="#شرح-الحقول" aria-label="Permalink to &quot;شرح الحقول&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الحقل</th><th>وظيفته</th><th>مطلوب</th></tr></thead><tbody><tr><td>اسم القناة</td><td>اسم واضح لقناة WebDAV، مثل <code>koofr</code> أو <code>nas</code>.</td><td>نعم</td></tr><tr><td>Endpoint</td><td>WebDAV endpoint كاملًا، مع <code>https://</code>.</td><td>نعم</td></tr><tr><td>Username</td><td>اسم مستخدم WebDAV.</td><td>نعم</td></tr><tr><td>Password</td><td>كلمة مرور WebDAV.</td><td>نعم</td></tr><tr><td>Authentication mode</td><td>غالبًا <code>Basic</code>؛ استخدم <code>Digest</code> إذا كان الخادم يتطلب digest authentication.</td><td>نعم</td></tr><tr><td>Storage directory</td><td>المجلد الذي تُحفظ فيه الملفات. الافتراضي <code>imgbed</code>.</td><td>لا</td></tr></tbody></table><h2 id="مثال-fie-nl-tab-digital" tabindex="-1">مثال: fie.nl.tab.digital <a class="header-anchor" href="#مثال-fie-nl-tab-digital" aria-label="Permalink to &quot;مثال: fie.nl.tab.digital&quot;">​</a></h2><h3 id="_1-أنشئ-app-password" tabindex="-1">1. أنشئ App Password <a class="header-anchor" href="#_1-أنشئ-app-password" aria-label="Permalink to &quot;1. أنشئ App Password&quot;">​</a></h3><p>افتح إعدادات أمان حسابك، وابحث عن application passwords، ثم أنشئ app password جديدًا.</p><p><img src="'+a+'" alt="إنشاء app password" loading="lazy"></p><p>بعد إنشائه انسخ كلمة المرور الجديدة واحفظها. غالبًا تظهر مرة واحدة فقط.</p><p><img src="'+e+'" alt="حفظ app password الجديد" loading="lazy"></p><h3 id="_2-املأ-إعداد-webdav-في-imgbed" tabindex="-1">2. املأ إعداد WebDAV في ImgBed <a class="header-anchor" href="#_2-املأ-إعداد-webdav-في-imgbed" aria-label="Permalink to &quot;2. املأ إعداد WebDAV في ImgBed&quot;">​</a></h3><p>ارجع إلى ImgBed وأضف قناة WebDAV:</p><table tabindex="0"><thead><tr><th>حقل الواجهة</th><th>القيمة</th></tr></thead><tbody><tr><td>Endpoint</td><td>عنوان WebDAV الذي يقدمه <code>https://fie.nl.tab.digital/</code>.</td></tr><tr><td>Username</td><td>اسم مستخدم WebDAV الخاص بك.</td></tr><tr><td>Password</td><td>app password الذي أنشأته للتو.</td></tr><tr><td>Authentication mode</td><td>ابدأ بـ <code>Basic</code> في معظم الحالات.</td></tr><tr><td>Storage directory</td><td>الافتراضي <code>imgbed</code>، ويمكنك استخدام مجلد مخصص.</td></tr></tbody></table><p><img src="'+d+'" alt="ملء الإعداد" loading="lazy"></p><h2 id="سلوك-رفع-الملفات-الكبيرة" tabindex="-1">سلوك رفع الملفات الكبيرة <a class="header-anchor" href="#سلوك-رفع-الملفات-الكبيرة" aria-label="Permalink to &quot;سلوك رفع الملفات الكبيرة&quot;">​</a></h2><p>تستخدم قناة WebDAV رفعًا مجزأً حقيقيًا قائمًا على الجلسة.</p><p>تُرفع الملفات الصغيرة كملف كامل واحد. أما الملفات الأكبر من 64 MiB فتُقسّم تلقائيًا إلى أجزاء بحجم يقارب 10 MiB وتُرفع إلى مجلد أجزاء بعيد.</p><p>لا تحتاج خدمة WebDAV إلى دعم <code>partial update</code> أو الكتابة حسب offset. لا يدمج ImgBed الأجزاء في ملف كبير واحد على الخادم البعيد. بدلًا من ذلك يحفظ manifest للأجزاء ويقرأها بالترتيب عند طلب الملف.</p><p>عمليًا:</p><table tabindex="0"><thead><tr><th>حجم الملف</th><th>طريقة الرفع</th><th>شكل التخزين البعيد</th></tr></thead><tbody><tr><td>64 MiB أو أقل</td><td>رفع عادي</td><td>ملف كامل واحد</td></tr><tr><td>أكبر من 64 MiB</td><td>رفع مجزأ حقيقي حسب الجلسة</td><td>مجلد أجزاء يحتوي عدة ملفات جزء</td></tr></tbody></table><p>مجلد الأجزاء يؤثر فقط على ترتيب التخزين البعيد. لا يغيّر رابط الملف في ImgBed. سيظل المستخدمون يصلون إلى الملف عبر الرابط الأصلي <code>/file/...</code>.</p><h2 id="خطوات-الإعداد" tabindex="-1">خطوات الإعداد <a class="header-anchor" href="#خطوات-الإعداد" aria-label="Permalink to &quot;خطوات الإعداد&quot;">​</a></h2><ol><li>افتح إعدادات الرفع.</li><li>اضغط Add Channel.</li><li>اختر <code>WebDAV</code>.</li><li>أدخل اسم قناة واضحًا، مثل <code>koofr</code>.</li><li>أدخل WebDAV endpoint، مثل <code>https://app.koofr.net/dav/Koofr</code>.</li><li>أدخل اسم المستخدم وكلمة المرور.</li><li>اترك authentication mode على <code>Basic</code> افتراضيًا.</li><li>اترك storage directory على <code>imgbed</code> أو غيّره إلى مجلدك.</li><li>اضغط Save.</li><li>بعد الحفظ تحقق من بطاقة القناة، واستعلم عن السعة إن كانت متاحة، وارفع ملفًا تجريبيًا.</li></ol><h2 id="كيف-تتحقق؟" tabindex="-1">كيف تتحقق؟ <a class="header-anchor" href="#كيف-تتحقق؟" aria-label="Permalink to &quot;كيف تتحقق؟&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الفحص</th><th>طريقة التحقق</th></tr></thead><tbody><tr><td>ظهور بطاقة القناة</td><td>بعد الحفظ يجب أن تظهر بطاقة قناة WebDAV في إعدادات الرفع.</td></tr><tr><td>القناة مفعلة</td><td>يجب أن يبقى المفتاح في أعلى يمين البطاقة مفعّلًا.</td></tr><tr><td>حفظ بيانات الاعتماد</td><td>يجب أن تظهر في التفاصيل قيم Endpoint و username و authentication mode و storage directory.</td></tr><tr><td>رفع ملف صغير يعمل</td><td>ارفع صورة تجريبية وتأكد من ظهور الملف في مجلد WebDAV.</td></tr><tr><td>قاعدة الملفات الكبيرة تعمل</td><td>الملفات الأكبر من 64 MiB تستخدم الرفع المجزأ وتنشئ مجلد أجزاء بعيدًا.</td></tr><tr><td>استعلام السعة يعمل</td><td>إذا كان الخادم يدعم معلومات السعة، سيعرض الاستعلام السعة المستخدمة والإجمالية.</td></tr></tbody></table><p><img src="'+o+`" alt="نجاح استعلام الحصة" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="لماذا-تنشئ-ملفات-webdav-الكبيرة-مجلد-أجزاء؟" tabindex="-1">لماذا تنشئ ملفات WebDAV الكبيرة مجلد أجزاء؟ <a class="header-anchor" href="#لماذا-تنشئ-ملفات-webdav-الكبيرة-مجلد-أجزاء؟" aria-label="Permalink to &quot;لماذا تنشئ ملفات WebDAV الكبيرة مجلد أجزاء؟&quot;">​</a></h3><p>هذه هي طريقة التخزين الحالية للملفات الكبيرة.</p><p>الملفات الأكبر من 64 MiB لا تُدمج في ملف بعيد واحد. تُحفظ كمجلد أجزاء. يسجل ImgBed manifest الأجزاء ويعيد المحتوى الكامل بقراءة الأجزاء بالترتيب.</p><h3 id="ماذا-أفحص-أولًا-إذا-فشل-رفع-ملف-كبير؟" tabindex="-1">ماذا أفحص أولًا إذا فشل رفع ملف كبير؟ <a class="header-anchor" href="#ماذا-أفحص-أولًا-إذا-فشل-رفع-ملف-كبير؟" aria-label="Permalink to &quot;ماذا أفحص أولًا إذا فشل رفع ملف كبير؟&quot;">​</a></h3><p>افحص Endpoint واسم المستخدم وكلمة المرور و storage directory أولًا. ثم تأكد أن خدمة WebDAV تسمح بإنشاء المجلدات وكتابة الملفات وقراءتها.</p><p>إذا فشل استعلام السعة لكن رفع الملفات الصغيرة يعمل، فقد يكون الخادم لا يدعم عرض السعة أو يقيّده. هذا لا يعني بالضرورة أن الرفع غير متاح.</p><h3 id="أي-authentication-mode-أستخدم؟" tabindex="-1">أي authentication mode أستخدم؟ <a class="header-anchor" href="#أي-authentication-mode-أستخدم؟" aria-label="Permalink to &quot;أي authentication mode أستخدم؟&quot;">​</a></h3><p>ابدأ بـ <code>Basic</code>.</p><p>إذا كان الخادم يتطلب digest authentication صراحة، استخدم <code>Digest</code>.</p><p>إذا لم تكن متأكدًا، استخدم التفاوض التلقائي.</p><h2 id="قائمة-تحقق-سريعة" tabindex="-1">قائمة تحقق سريعة <a class="header-anchor" href="#قائمة-تحقق-سريعة" aria-label="Permalink to &quot;قائمة تحقق سريعة&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>جهّز WebDAV endpoint و username و password</span></span>
<span class="line"><span>-&gt; افتح إعدادات الرفع</span></span>
<span class="line"><span>-&gt; أضف قناة</span></span>
<span class="line"><span>-&gt; اختر WebDAV</span></span>
<span class="line"><span>-&gt; أدخل Endpoint / username / password</span></span>
<span class="line"><span>-&gt; اترك authentication mode على Basic افتراضيًا</span></span>
<span class="line"><span>-&gt; اترك storage directory على imgbed افتراضيًا</span></span>
<span class="line"><span>-&gt; احفظ</span></span>
<span class="line"><span>-&gt; استعلم عن السعة</span></span>
<span class="line"><span>-&gt; ارفع ملفًا تجريبيًا</span></span></code></pre></div>`,45)])])}const D=i(l,[["render",p]]);export{f as __pageData,D as default};
